manifest.Script:
function searchAmazon(query) {
  Me.Frame.Navigate("search");

  setTimeout(() => {
    const results = document.getElementById("results-container");
    results.innerHTML = `
      <p>Resultados para "<strong>${query}</strong>"...</p>
    `;
  }, 50);
}

function addToCart() {
  notify("amazon", "Producto añadido al carrito!");
}

function checkout() {
  alert("Gracias por comprar en Amazon!");
}

manifest.Stylesheet:
.screen {
  background-color: #232f3e;
  color: #fff;
  font-family: "Roboto Flex", sans-serif;
}

.serious-header {
  font-size: 24px;
  font-weight: bold;
  padding: 16px;
  background-color: #37475a;
  text-align: center;
}

.scroll-area {
  padding: 16px;
  overflow-y: auto;
}

.category-bt {
  background-color: #ff9900;
  color: black;
  padding: 10px 16px;
  margin: 8px 0;
  border-radius: 4px;
  cursor: pointer;
}

.category-bt:hover {
  background-color: #e68a00;
}

button {
  background-color: #ff9900;
  border: none;
  padding: 10px 16px;
  margin-top: 16px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 16px;
}

button:hover {
  background-color: #e68a00;
}

input[type="text"] {
  width: 100%;
  padding: 10px;
  margin-bottom: 12px;
  border: none;
  border-radius: 4px;
  font-size: 16px;
}

.loader {
  width: 40px;
  height: 40px;
  border: 4px solid #ff9900;
  border-top: 4px solid transparent;
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 20px auto;
  display: none;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}
